def column_integrity_check(ground_truth):
    import pandas as pd
    output = pd.read_csv("output.csv")
    expected_columns = ground_truth.columns.tolist()
    actual_columns = output.columns.tolist()
    return set(expected_columns) == set(actual_columns)

