def data_consistency_check(ground_truth):
    import pandas as pd
    output = pd.read_csv("output.csv")
    merged_df = pd.merge(ground_truth, output, on='Id', how='inner', suffixes=('_gt', '_out'))
    return merged_df['Password_out'].equals(merged_df['Password_gt'])

