Function1:
def visualization_completeness(ground_truth):
    import pandas as pd
    import os

    # Load the ground truth visualizations filenames
    ground_truth = set(ground_truth)

    # Check if the output files exist
    output_files = {
        'distribution_by_country.png',
        'sales_trends_over_time.png',
        'correlation_heatmap.png'
    }

    existing_files = set(os.listdir('./'))  # Assuming output files are in current directory
    return len(ground_truth.intersection(existing_files)) == len(output_files)

Function2:
def clustering_silhouette_score(ground_truth):
    import pandas as pd
    from sklearn.metrics import silhouette_score
    output = pd.read_csv("clusters.csv")
    # Assuming the clustering results include a column 'Cluster' and the original features are available in cleaned_data
    features = pd.read_csv("cleaned_data.csv").drop(columns=['Country'])  # Drop non-feature columns like country name
    if 'Cluster' in output.columns:
        features['Cluster'] = output['Cluster']
        return silhouette_score(features.drop(columns=['Cluster']), features['Cluster'])
    else:
        raise ValueError("Cluster column not found in clusters.csv")

