def summary_statistics_consistency(ground_truth):
    import pandas as pd
    output = pd.read_csv("eda_statistics.csv")
    original_stats = ground_truth.describe(include='all')
    computed_stats = output.iloc[0]  # Assuming first row contains the statistics for numerical features
    return original_stats.equals(computed_stats)

