Function3:
def z_score_normalization_check(ground_truth):
    import pandas as pd
    output = pd.read_csv("normalized_data.csv")
    # Calculate Z-scores for the 'Age', 'BloodPressure', and 'Cholesterol' in the ground truth
    normalized_ground_truth = (ground_truth[['Age', 'BloodPressure', 'Cholesterol']] - ground_truth[['Age', 'BloodPressure', 'Cholesterol']].mean()) / ground_truth[['Age', 'BloodPressure', 'Cholesterol']].std()
    return (output[['Age', 'BloodPressure', 'Cholesterol']] == normalized_ground_truth).all().all()

Function5:
def patient_id_consistency_check(ground_truth):
    import pandas as pd
    output = pd.read_csv("final_cleaned_data.csv")
    # Check if PatientID is of string type and matches the ground truth
    return output['PatientID'].dtype == 'object' and output['PatientID'].equals(ground_truth['PatientID'].astype(str))

Function3:
def normalization_check(ground_truth):
    import pandas as pd
    output = pd.read_csv("normalized_data.csv")
    quantity_range = output['Quantity'].max() - output['Quantity'].min()
    unit_price_range = output['UnitPrice'].max() - output['UnitPrice'].min()
    return (quantity_range, unit_price_range)

Function4:
def invoice_date_format_validation(ground_truth):
    import pandas as pd
    output = pd.read_csv("data_with_datetime.csv")
    return pd.to_datetime(output['InvoiceDate'], errors='coerce').notna().all()

Function1:
def mean_absolute_error_missing(ground_truth):
    import pandas as pd
    output = pd.read_csv("missing_values_handled.csv")
    return (output[['Temperature', 'Humidity', 'WindSpeed']] - ground_truth[['Temperature', 'Humidity', 'WindSpeed']]).abs().mean().mean()

Function3:
def min_max_scaling_range(ground_truth):
    import pandas as pd
    output = pd.read_csv("normalized_data.csv")
    min_vals = output[['Temperature', 'Humidity', 'WindSpeed']].min()
    max_vals = output[['Temperature', 'Humidity', 'WindSpeed']].max()
    return (max_vals - min_vals).sum()

Function4:
def verify_date_format(ground_truth):
    import pandas as pd
    output = pd.read_csv("date_formatted.csv")
    return pd.to_datetime(output['Date'], errors='coerce').notna().all()

Function5:
def one_hot_encoding_consistency(ground_truth):
    import pandas as pd
    output = pd.read_csv("final_cleaned_data.csv")
    unique_station_ids = ground_truth['StationID'].unique()
    return all(station_id in output.columns for station_id in unique_station_ids)
